import{_ as e,o as r,c as t,a2 as s}from"./chunks/framework.BS3ZfcoS.js";const p=JSON.parse('{"title":"如何变富","description":"","frontmatter":{"title":"如何变富","author":"","collection":"职场成长","series_order":5,"total_chars":1064},"headers":[],"relativePath":"career/how-to-get-rich.md","filePath":"career/how-to-get-rich.md"}'),o={name:"career/how-to-get-rich.md"};function h(i,a,n,l,d,c){return r(),t("div",null,[...a[0]||(a[0]=[s('<h2 id="s-394" tabindex="-1">如何变富系列 <a class="header-anchor" href="#s-394" aria-label="Permalink to &quot;如何变富系列 {#s-394}&quot;">​</a></h2><p>共4个视频</p><h3 id="s-395" tabindex="-1">如何变富：没人告诉你的金钱真相｜为什么打工无法让你变富？（完整版） <a class="header-anchor" href="#s-395" aria-label="Permalink to &quot;如何变富：没人告诉你的金钱真相｜为什么打工无法让你变富？（完整版） {#s-395}&quot;">​</a></h3><p><strong>核心观点</strong></p><p>**1. **挣钱分三个段位：出卖时间（碎片）→产品和服务（独立个体）→商业杠杆（系统）</p><h4 id="s-396" tabindex="-1">2. 企业是劳动经纪人，抽成至少九成——年薪百万需为公司创造千万利润 <a class="header-anchor" href="#s-396" aria-label="Permalink to &quot;2. 企业是劳动经纪人，抽成至少九成——年薪百万需为公司创造千万利润 {#s-396}&quot;">​</a></h4><h4 id="s-397" tabindex="-1">3. 打工困境：优质时间给公司，劣质时间留自己→消费→再分配→老鼠赛跑陷阱 <a class="header-anchor" href="#s-397" aria-label="Permalink to &quot;3. 打工困境：优质时间给公司，劣质时间留自己→消费→再分配→老鼠赛跑陷阱 {#s-397}&quot;">​</a></h4><h4 id="s-398" tabindex="-1">4. 第一段位出路：提升价值创造力、跳槽涨薪、用动态眼光看待收入增长 <a class="header-anchor" href="#s-398" aria-label="Permalink to &quot;4. 第一段位出路：提升价值创造力、跳槽涨薪、用动态眼光看待收入增长 {#s-398}&quot;">​</a></h4><h4 id="s-399" tabindex="-1">5. 挣钱教育从小到大是空白甚至错误的 <a class="header-anchor" href="#s-399" aria-label="Permalink to &quot;5. 挣钱教育从小到大是空白甚至错误的 {#s-399}&quot;">​</a></h4><p><strong>金句</strong></p><p><em>「人的一切痛苦，本质上都是来自于对自己无能的愤怒」</em></p><p><strong>行动指南</strong></p><p>评估自己当前挣钱段位，制定向下一阶段跃迁的行动路径</p><h3 id="s-400" tabindex="-1">如何变富：没人告诉你的金钱真相｜三种商业杠杆 <a class="header-anchor" href="#s-400" aria-label="Permalink to &quot;如何变富：没人告诉你的金钱真相｜三种商业杠杆 {#s-400}&quot;">​</a></h3><p><strong>核心观点</strong></p><p>**1. **三种商业杠杆：劳动力杠杆（最落后，管理复杂）、资本杠杆（放大效应明显，考验判断力）、复制边际成本为零的产品（普通人最可及）</p><h4 id="s-401" tabindex="-1">2. 代码和媒体杠杆不需要任何人允许，一台电脑就能把劳动成果放大成千上万倍 <a class="header-anchor" href="#s-401" aria-label="Permalink to &quot;2. 代码和媒体杠杆不需要任何人允许，一台电脑就能把劳动成果放大成千上万倍 {#s-401}&quot;">​</a></h4><h4 id="s-402" tabindex="-1">3. 使用杠杆前提是先有自己的专长，否则杠杆只会放大缺陷 <a class="header-anchor" href="#s-402" aria-label="Permalink to &quot;3. 使用杠杆前提是先有自己的专长，否则杠杆只会放大缺陷 {#s-402}&quot;">​</a></h4><h4 id="s-403" tabindex="-1">4. 三种阻碍杠杆的认知：畏惧风险、畏惧舆论暴露、不相信自己能变富 <a class="header-anchor" href="#s-403" aria-label="Permalink to &quot;4. 三种阻碍杠杆的认知：畏惧风险、畏惧舆论暴露、不相信自己能变富 {#s-403}&quot;">​</a></h4><h4 id="s-404" tabindex="-1">5. 玩金钱游戏而非地位游戏——攻击他人显示自己是地位游戏，创造财富才是正道 <a class="header-anchor" href="#s-404" aria-label="Permalink to &quot;5. 玩金钱游戏而非地位游戏——攻击他人显示自己是地位游戏，创造财富才是正道 {#s-404}&quot;">​</a></h4><p><strong>金句</strong></p><p><em>「只要你有一台电脑，你就能够把自己劳动成果放大成千上万倍」</em></p><p><strong>行动指南</strong></p><p>思考自己能用哪种杠杆，先建立一技之长再使用杠杆放大</p><h3 id="s-405" tabindex="-1">如何变富：没人告诉你的金钱真相｜第二段位——产品与服务 <a class="header-anchor" href="#s-405" aria-label="Permalink to &quot;如何变富：没人告诉你的金钱真相｜第二段位——产品与服务 {#s-405}&quot;">​</a></h3><p><strong>核心观点</strong></p><h4 id="s-406" tabindex="-1">1. 第二段位：靠产品和服务挣钱，成为独立个体——把自己产品化 <a class="header-anchor" href="#s-406" aria-label="Permalink to &quot;1. 第二段位：靠产品和服务挣钱，成为独立个体——把自己产品化 {#s-406}&quot;">​</a></h4><h4 id="s-407" tabindex="-1">2. 找独特价值点要依托天赋和专长，在自己道路上没人能比得过你 <a class="header-anchor" href="#s-407" aria-label="Permalink to &quot;2. 找独特价值点要依托天赋和专长，在自己道路上没人能比得过你 {#s-407}&quot;">​</a></h4><h4 id="s-408" tabindex="-1">3. 挣多少钱不取决于你多厉害，而取决于你服务的人有多有钱 <a class="header-anchor" href="#s-408" aria-label="Permalink to &quot;3. 挣多少钱不取决于你多厉害，而取决于你服务的人有多有钱 {#s-408}&quot;">​</a></h4><h4 id="s-409" tabindex="-1">4. &quot;宁愿挣富人的零花钱，也不要挣穷人的生活费&quot; <a class="header-anchor" href="#s-409" aria-label="Permalink to &quot;4. &quot;宁愿挣富人的零花钱，也不要挣穷人的生活费&quot; {#s-409}&quot;">​</a></h4><h4 id="s-410" tabindex="-1">5. 要服务更多人就需要产品规模化，于是需要商业杠杆 <a class="header-anchor" href="#s-410" aria-label="Permalink to &quot;5. 要服务更多人就需要产品规模化，于是需要商业杠杆 {#s-410}&quot;">​</a></h4><p><strong>金句</strong></p><p><em>「在你做自己的道路上，没有人能够比得过你」</em></p><p><strong>行动指南</strong></p><p>找到自己的独特价值点，选择服务更有支付能力的客户群体</p><h3 id="s-411" tabindex="-1">如何变富：没人告诉你的金钱真相｜第一段位详解 <a class="header-anchor" href="#s-411" aria-label="Permalink to &quot;如何变富：没人告诉你的金钱真相｜第一段位详解 {#s-411}&quot;">​</a></h3><p><strong>核心观点</strong></p><h4 id="s-412" tabindex="-1">1. 企业抽成九成起——年薪百万需创造千万利润，收益经过层层分配所剩无几 <a class="header-anchor" href="#s-412" aria-label="Permalink to &quot;1. 企业抽成九成起——年薪百万需创造千万利润，收益经过层层分配所剩无几 {#s-412}&quot;">​</a></h4><h4 id="s-413" tabindex="-1">2. 工作拿走优质时间、留下劣质时间→消费→再分配→老鼠赛跑陷阱 <a class="header-anchor" href="#s-413" aria-label="Permalink to &quot;2. 工作拿走优质时间、留下劣质时间→消费→再分配→老鼠赛跑陷阱 {#s-413}&quot;">​</a></h4><h4 id="s-414" tabindex="-1">3. 不能用静态眼光看待收入，认真工作会不断变好 <a class="header-anchor" href="#s-414" aria-label="Permalink to &quot;3. 不能用静态眼光看待收入，认真工作会不断变好 {#s-414}&quot;">​</a></h4><h4 id="s-415" tabindex="-1">4. 可以&quot;压榨&quot;工作带来的成长和价值来对抗被压榨 <a class="header-anchor" href="#s-415" aria-label="Permalink to &quot;4. 可以&quot;压榨&quot;工作带来的成长和价值来对抗被压榨 {#s-415}&quot;">​</a></h4><h4 id="s-416" tabindex="-1">5. 第一段位解法：提升价值创造力、跳槽实现收入跃迁 <a class="header-anchor" href="#s-416" aria-label="Permalink to &quot;5. 第一段位解法：提升价值创造力、跳槽实现收入跃迁 {#s-416}&quot;">​</a></h4><p><strong>金句</strong></p><p><em>「你不能用静态的眼光去看待自己的收入」</em></p><p><strong>行动指南</strong></p><p>在工作中提升核心能力，通过出色项目和跳槽实现收入跃迁</p>',46)])])}const q=e(o,[["render",h]]);export{p as __pageData,q as default};
